class LoanCalculator {
    private static final double ANNUAL_INTEREST_RATE_STANDARD = 0.05;
    private static final int MONTHS_PER_YEAR = 12;

    Money calculateMonthlyPayment(Money principal, int termInYears) {
        double monthlyInterestRate = ANNUAL_INTEREST_RATE_STANDARD / MONTHS_PER_YEAR;
        int numberOfMonthlyPayments = termInYears * MONTHS_PER_YEAR;
        double paymentFactor = monthlyInterestRate
            / (1 - Math.pow(1 + monthlyInterestRate, -numberOfMonthlyPayments));
        return principal.multipliedBy(paymentFactor);
    }
}
